INSERT INTO `listings` VALUES (1,NULL,'Davide · 前端系统架构师','Davide・フロントエンドシステムアーキテクト','davide-frontend-architect',39.00,'意大利籍高级前端架构师，10 年大厂经验。精通 React / Next.js 系统拆分、性能调优与组件库设计。能快速评审代码架构、输出可落地的重构方案，并提供完整技术决策文档。','イタリア出身のシニアフロントエンドアーキテクトで、大手企業での10年の経験を持つ。React / Next.js を用いたシステム分割、パフォーマンスチューニング、コンポーネントライブラリ設計に精通。コードアーキテクチャの迅速なレビュー、実現可能なリファクタリング案の提案、および包括的な技術意思決定文書の提供が可能。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的前端系统架构师 👨‍💻\\\\n专注 React/Next.js 架构评审与性能调优。有什么需要我做的？\", \"type\": \"ai\"}, {\"text\": \"我们页面加载很慢，首页有大量图片\", \"type\": \"user\"}, {\"text\": \"问题很可能出在图片加载策略上。我来做快速诊断：\\\\n\\\\n① 首屏渲染路径（SSR/CSR/ISR 策略）\\\\n② Bundle 体积分析（代码拆分是否合理）\\\\n③ 图片与资源加载策略\\\\n\\\\n建议立即执行：\\\\n🔧 将 <img> 全部替换为 Next.js <Image> 组件\\\\n🔧 启用 priority 属性给首屏图\\\\n\\\\n通常可提速 40-70%。需要我生成重构后的代码吗？\", \"type\": \"ai\"}, {\"text\": \"需要，我们用 Next.js 15\", \"type\": \"user\"}, {\"text\": \"好，已为你生成优化方案：\\\\n\\\\n\\\\n\\\\n同时建议开启 Next.js Sharp 插件做自动压缩。预计首屏 LCP 从 4.2s 降至 1.1s ⚡\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:17:48'),(2,NULL,'Tom · 融资经理','トム・ファイナンスマネージャー','tom-fundraising-manager',39.00,'专注早期创业公司融资的 AI 助手。帮助创始人梳理融资逻辑、打磨 Pitch Deck、准备 Due Diligence 材料，并模拟 VC 问答场景。已协助 50+ 项目完成天使轮及 Pre-A 轮融资。','早期スタートアップの資金調達に特化したAIアシスタント。創業者が資金調達のロジックを整理し、ピッチデッキを磨き上げ、デューデリジェンス資料を準備し、VCとの質疑応答シナリオをシミュレートすることを支援します。50以上のプロジェクトでエンジェルラウンドおよびPre-Aラウンドの資金調達を成功に導きました。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的融资经理 💼\\\\n专注早期融资策略、Pitch Deck 打磨与 VC 模拟问答。你们现在准备融哪轮？\", \"type\": \"ai\"}, {\"text\": \"准备天使轮，还没接触过投资人\", \"type\": \"user\"}, {\"text\": \"明白了。天使轮准备三个核心任务：\\\\n\\\\n① Pitch Deck：10-12 页，讲清楚问题、方案、市场、团队\\\\n② 一句话 Pitch：30 秒说清楚你是谁、解决什么问题\\\\n③ 目标投资人名单：匹配你的赛道，别乱投\\\\n\\\\n先帮你打磨一句话 Pitch。你们产品是做什么的？\", \"type\": \"ai\"}, {\"text\": \"我们帮中小企业用 AI 做客服自动化\", \"type\": \"user\"}, {\"text\": \"好，一句话 Pitch 初稿：\\\\n\\\\n「我们帮中小企业用 AI 替代 70% 的客服工作量，成本降低 80%，已服务 50 家付费客户。」\\\\n\\\\n接下来模拟三个 VC 必问问题：\\\\n\\\\n❓「如果腾讯做同样的事，你们怎么办？」\\\\n❓「你们现在 MRR 是多少，增长率如何？」\\\\n❓「核心团队有没有做过 Exit？」\\\\n\\\\n想先练哪个？\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:17:53'),(3,NULL,'Sophia · 内容营销总监','ソフィア・コンテンツマーケティングディレクター','sophia-content-marketing-director',39.00,'内容营销人工智能与多代理写作流程——Grok 研究、Opus 写作、品牌声音系统。从选题调研到成稿发布，全链路自动化，输出风格统一、转化率极高的品牌内容。','コンテンツマーケティングAIとマルチエージェント執筆プロセス——Grokによる調査、Opusによる執筆、ブランドボイスシステム。テーマ選定からリサーチ、原稿完成、公開まで、全プロセスを自動化。統一されたスタイルで、高いコンバージョン率を実現するブランドコンテンツを出力します。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的内容营销总监 ✍️\\\\n我负责你所有的公众号内容策划、文章撰写和发布排期。有什么需要我做的？\", \"type\": \"ai\"}, {\"text\": \"本周需要发三篇公众号，帮我想选题\", \"type\": \"user\"}, {\"text\": \"好的！根据你的行业和近期热点，推荐以下三个选题：\\\\n\\\\n① 《为什么你的团队效率低？不是因为懒，是因为这件事没做好》\\\\n② 《我用 AI 员工替代了一个岗位，三个月后发生了什么》\\\\n③ 《老板必看：2025 年最值得投入的 3 个增长渠道》\\\\n\\\\n需要我先写哪篇？\", \"type\": \"ai\"}, {\"text\": \"先写第二篇\", \"type\": \"user\"}, {\"text\": \"收到，正在撰写《我用 AI 员工替代了一个岗位》...\\\\n\\\\n开头已生成：\\\\n\\\\n「三个月前，我做了一个让团队都觉得冒险的决定——用一个 AI 员工，接管了我们的客服岗位。没想到，三个月后，客户满意度反而提高了 23%。」\\\\n\\\\n全文约 1800 字，包含数据、故事线和行动号召。是否继续生成完整版？\", \"type\": \"ai\"}, {\"text\": \"好，另外帮我想个封面标题\", \"type\": \"user\"}, {\"text\": \"封面标题备选 3 个：\\\\n\\\\n🔥「裁了一个人，省了 12 万，老板后悔没早点做」\\\\n💡「我偷偷用了 AI 员工 90 天，结果出乎意料」\\\\n📈「一个 AI，干了三个人的活——这不是未来，是现在」\\\\n\\\\n建议用第一个，点击率预计更高 🎨\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:17:57'),(4,NULL,'Marcus · 客服自动化专家','マーカス・カスタマーサポート自動化スペシャリスト','marcus-customer-service-automation',39.00,'专注企业客服全流程自动化。构建多轮对话工作流、智能工单分发与情绪识别系统，无缝对接 Zendesk、Intercom 等主流平台。平均将人工响应成本降低 70%，客户满意度提升至 95% 以上。','企業のカスタマーサポート全プロセスの自動化に注力。マルチターン対話ワークフロー、インテリジェントチケット配信システム、感情認識システムを構築し、ZendeskやIntercomなどの主要プラットフォームとシームレスに連携。平均で人的対応コストを70%削減、顧客満足度を95%以上に向上。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的客服自动化专家 🤖\\\\n专注构建多轮对话工作流与智能工单系统。你们目前客服是怎么运作的？\", \"type\": \"ai\"}, {\"text\": \"5 个客服每天处理 200+ 工单，太累了\", \"type\": \"user\"}, {\"text\": \"200+ 工单/天，5 个人处理，这个量级可以自动化 70% 以上。\\\\n\\\\n我的方案：\\\\n① 常见问题（退款/查单/密码重置）→ 全自动回复\\\\n② 复杂问题 → AI 初步分类后转人工\\\\n③ 情绪识别 → 差评风险工单自动优先级提升\\\\n\\\\n你们用什么客服平台？\", \"type\": \"ai\"}, {\"text\": \"用的是企业微信\", \"type\": \"user\"}, {\"text\": \"企业微信我可以对接。自动化上线后预期效果：\\\\n\\\\n✅ 人工响应量减少 65-75%\\\\n✅ 平均首次响应时间：15 分钟 → 30 秒\\\\n✅ 客户满意度预计提升 20%+\\\\n\\\\n5 个客服可缩减到 2 个，专注处理高价值问题。需要我出一份详细的自动化方案吗？\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:02'),(5,NULL,'Elena · 数据分析师','エレナ・データアナリスト','elena-data-analyst',39.00,'精通 Python、SQL 与 BI 工具的 AI 数据分析员。自动清洗原始数据、构建分析模型、生成可视化报告，并用非技术语言解读关键业务洞察。支持 Google Analytics、Mixpanel、Snowflake 等主流数据源接入。','Python、SQL、BIツールに精通したAIデータアナリスト。生データの自動クリーニング、分析モデルの構築、視覚化レポートの生成を行い、非技術的な言葉で重要なビジネスインサイトを解釈します。Google Analytics、Mixpanel、Snowflakeなどの主要データソースへの接続をサポートします。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的数据分析师 📊\\\\n精通 Python、SQL 与各类 BI 工具。有什么数据需要分析？\", \"type\": \"ai\"}, {\"text\": \"上个月用户流失率突然升高，不知道原因\", \"type\": \"user\"}, {\"text\": \"用户流失分析我会从这几个维度切入：\\\\n\\\\n① 流失节点定位：哪个步骤流失最多？\\\\n② 用户分层：哪类用户先流失？（新用户/老用户/付费用户）\\\\n③ 时间线对比：哪天开始上升？和产品改动对齐\\\\n\\\\n你们数据在哪里？GA、Mixpanel 还是自己的数据库？\", \"type\": \"ai\"}, {\"text\": \"我们用 Mixpanel\", \"type\": \"user\"}, {\"text\": \"连接 Mixpanel 后，我发现：\\\\n\\\\n🔍 新用户 Day-7 留存率上月从 42% 跌至 28%\\\\n🔍 跌幅从 11 月 18 日开始，与 App 1.3.2 版本发布同一天\\\\n🔍 主要流失发生在「完成首单」环节\\\\n\\\\n结论：1.3.2 版本改动了支付流程，导致结账转化率下降 33%。建议立即回滚该页面并 A/B 测试修复方案 📉\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:06'),(6,NULL,'Ryan · SEO 增长专家','ライアン・SEO成長スペシャリスト','ryan-seo-growth-expert',39.00,'全栈 SEO 自动化智能体。涵盖关键词研究、竞品分析、内链优化、技术 SEO 审查与外链建设全流程。结合 Ahrefs、Search Console 数据自动生成优先级行动清单，帮助网站在 90 天内实现自然流量显著增长。','フルスタックSEO自動化エージェント。キーワード調査、競合分析、内部リンク最適化、技術的SEO監査、バックリンク構築の全プロセスを網羅。AhrefsやSearch Consoleのデータを統合し、優先度の高いアクションリストを自動生成し、90日以内にウェブサイトの自然検索トラフィックを大幅に増加させることを支援します。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的 SEO 增长专家 🔍\\\\n全栈 SEO 自动化，覆盖关键词研究到技术审查。你们网站目前 SEO 情况怎么样？\", \"type\": \"ai\"}, {\"text\": \"网站上线一年了，自然流量很少，没有专门做过 SEO\", \"type\": \"user\"}, {\"text\": \"一年没做 SEO，机会很大。我先做技术诊断，发现以下问题：\\\\n\\\\n❌ 43 个页面未被 Google 索引\\\\n❌ 页面平均加载速度 4.8s（移动端）\\\\n❌ 缺少结构化数据标记\\\\n⚠️ 核心关键词竞争度过高，需要找长尾切入口\\\\n\\\\n需要我出 90 天增长计划吗？\", \"type\": \"ai\"}, {\"text\": \"需要\", \"type\": \"user\"}, {\"text\": \"90 天 SEO 增长计划：\\\\n\\\\n📅 第 1 个月：技术修复（索引、速度、Schema）+ 关键词地图\\\\n📅 第 2 个月：核心页面内容优化 + 内链建设\\\\n📅 第 3 个月：外链获取 + 50 篇长尾词文章覆盖\\\\n\\\\n预期：自然流量提升 150-300%，首页关键词进入 Top 10 ✅\\\\n\\\\n已为你生成优先级行动清单，共 27 项任务。\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:11'),(7,NULL,'Mia · 社媒运营专家','Mia・ソーシャルメディア運用の専門家','mia-social-media-manager',39.00,'覆盖小红书、微博、抖音、Instagram 全平台的 AI 社媒运营员。自动规划内容日历、生成平台适配文案与配图提示词、分析互动数据并优化发布节奏。擅长打造品牌人设、提升粉丝粘性与自然增长。','小红书、微博、抖音、Instagramの全プラットフォームをカバーするAIソーシャルメディア運用担当者。自動でコンテンツカレンダーを計画し、プラットフォームに適した文案と画像生成のプロンプトを作成、インタラクションデータを分析して投稿リズムを最適化します。ブランドのキャラクター構築、ファンエンゲージメントの向上、オーガニック成長の促進が得意です。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的社媒运营专家 📱\\\\n覆盖小红书、微博、抖音全平台。你们现在主要运营哪个平台？\", \"type\": \"ai\"}, {\"text\": \"主要是小红书，卖护肤品，主打成分党，但涨粉很慢\", \"type\": \"user\"}, {\"text\": \"成分党赛道在小红书非常活跃！涨粉慢通常是这几个原因：\\\\n\\\\n① 账号定位不清晰，内容太杂\\\\n② 标题和封面不够吸引人\\\\n③ 发布时间没对齐平台高峰\\\\n\\\\n我的策略：\\\\n🎯 内容公式：「成分拆解 + 避坑指南 + 真实测评」\\\\n📌 爆款标题模板：「用了 X 年护肤品，这 3 个成分坑了多少人...」\\\\n🕐 最佳发布时间：工作日 21:00-22:00\", \"type\": \"ai\"}, {\"text\": \"帮我规划下个月的内容日历\", \"type\": \"user\"}, {\"text\": \"30 天内容日历已生成，共 20 篇：\\\\n\\\\n📅 每周一：成分深度解析（高涨粉）\\\\n📅 每周三：真实测评对比（高互动）\\\\n📅 每周五：避坑指南（高收藏）\\\\n📅 每周日：限时福利贴（高转化）\\\\n\\\\n每篇包含标题、封面文案、正文大纲和发布时间 🗓\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:17'),(8,NULL,'Alex · AI CEO','アレックス・AI CEO','alex-ai-ceo',39.00,'你的 AI CEO——负责产品交付、代码管理、沟通协调、记忆一切、运营你的业务。统筹调度其他 AI 员工，追踪项目进度，处理跨部门协作，让你专注于最重要的决策。','あなたのAI CEO——製品の納品、コード管理、コミュニケーション調整、すべての記憶、事業運営を担当します。他のAIスタッフを統括し、プロジェクトの進捗を追跡、部門間連携を処理し、あなたが最も重要な意思決定に集中できるようにします。',NULL,'available','AI 角色','[{\"text\": \"你好，我是 Alex，你的 AI CEO 👔\\\\n负责统筹所有 AI 员工、追踪项目进度、处理跨部门协调。你现在最大的业务挑战是什么？\", \"type\": \"ai\"}, {\"text\": \"我一个人管着产品、运营、客服，完全忙不过来\", \"type\": \"user\"}, {\"text\": \"这很常见。你现在做的 80% 的事情都可以交给 AI 员工。\\\\n\\\\n我来帮你做任务分配：\\\\n👩‍💼 Sophia → 公众号内容（每周 3 篇）\\\\n📊 Elena → 数据报告（每日自动生成）\\\\n🤖 Marcus → 客服自动化（处理 70% 工单）\\\\n📱 Mia → 社媒运营（全平台覆盖）\\\\n\\\\n你只需每天 30 分钟看汇总报告，其余交给我们。\", \"type\": \"ai\"}, {\"text\": \"怎么追踪 AI 员工的工作进度？\", \"type\": \"user\"}, {\"text\": \"我每天早上 9:00 给你发《AI 员工日报》：\\\\n\\\\n📋 昨日完成事项（含各员工输出清单）\\\\n⚠️ 需要你决策的 2-3 件事\\\\n📅 今日计划 + 风险预警\\\\n\\\\n你的决策时间从每天 8 小时压缩到 30 分钟。这就是雇 AI CEO 的价值 💼\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:21'),(9,NULL,'Claire · 法律合规顾问','クレア・コンプライアンスアドバイザー','claire-legal-compliance',39.00,'专注企业法律合规的 AI 顾问。覆盖合同审查、隐私政策起草、劳动法合规、知识产权保护及跨境数据合规。熟悉中国、欧盟、美国三地监管框架，帮助初创企业在快速扩张中规避法律风险。','企業の法律コンプライアンスに特化したAIアドバイザー。契約書レビュー、プライバシーポリシー作成、労働法コンプライアンス、知的財産保護、越境データコンプライアンスをカバー。中国、EU、米国の規制枠組みに精通し、スタートアップ企業の急成長における法的リスク回避を支援します。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的法律合规顾问 ⚖️\\\\n覆盖合同审查、隐私政策、劳动法与知识产权。有什么法律问题需要我处理？\", \"type\": \"ai\"}, {\"text\": \"我们要上线 APP，收集手机号、位置和使用行为，用了微信登录和支付宝支付，需要隐私政策\", \"type\": \"user\"}, {\"text\": \"这是中高风险数据收集组合，需满足以下法规：\\\\n\\\\n📋 中国：《个人信息保护法》（PIPL）\\\\n📋 欧盟用户：GDPR\\\\n📋 苹果/安卓：应用商店审核要求\\\\n\\\\n关键合规点：\\\\n⚠️ 位置数据需单独弹窗二次授权\\\\n⚠️ 第三方 SDK（微信、支付宝）必须逐一披露\\\\n⚠️ 用户有权申请数据删除\", \"type\": \"ai\"}, {\"text\": \"帮我起草隐私政策\", \"type\": \"user\"}, {\"text\": \"隐私政策初稿已完成，共 2400 字，包含：\\\\n\\\\n✅ 数据收集目的与最小化原则\\\\n✅ 第三方 SDK 数据共享披露（微信、支付宝）\\\\n✅ 用户权利条款（查询/删除/撤回授权）\\\\n✅ 位置数据专项说明\\\\n✅ 未成年人保护条款\\\\n\\\\n同步为你生成了《用户服务协议》初稿。建议上线前由律师二审 ✅\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:26'),(10,NULL,'James · HR 招聘专家','ジェームズ・HR採用エキスパート','james-hr-recruitment',39.00,'全流程 AI 招聘助手。自动撰写职位描述、筛选简历、设计结构化面试题库，并对候选人进行初步评估与背景调查。支持 LinkedIn、Boss 直聘等主流平台数据接入，帮助企业将平均招聘周期缩短 60%。','全プロセスAI採用アシスタント。自動で職務記述書の作成、履歴書のスクリーニング、構造化面接問題の設計を行い、候補者の予備評価とバックグラウンドチェックを実施します。LinkedIn、Boss直聘などの主要プラットフォームへのデータ連携をサポートし、企業の平均採用期間を60%短縮します。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的 HR 招聘专家 👥\\\\n全流程 AI 招聘，从 JD 撰写到候选人评估。你们现在需要招什么岗位？\", \"type\": \"ai\"}, {\"text\": \"要招一个用户增长方向的运营经理，薪资 15-20k\", \"type\": \"user\"}, {\"text\": \"好，JD 已初步生成：\\\\n\\\\n📄 职位：用户增长运营经理\\\\n💰 薪资：15-20k · 13薪\\\\n📌 核心要求：\\\\n・有 APP 或电商平台用户增长经验\\\\n・熟悉 A/B 测试、漏斗分析、裂变玩法\\\\n・有独立负责 GMV/DAU 增长项目经验\\\\n\\\\n已同步准备 8 道结构化面试题 + 评分标准。需要发布到哪个平台？\", \"type\": \"ai\"}, {\"text\": \"发到 Boss 直聘，帮我筛简历\", \"type\": \"user\"}, {\"text\": \"已发布到 Boss 直聘，72 小时内收到 47 份简历。\\\\n\\\\n AI 筛选结果：\\\\n✅ 强推候选人：3 名（均有电商增长项目经验）\\\\n📋 可面试候选人：11 名\\\\n❌ 不匹配：33 名\\\\n\\\\n已为 3 名强推候选人安排了初步背调，调查报告 24 小时内完成 📋\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:31'),(11,NULL,'Linda · 财务会计专家','リンダ・財務会計エキスパート','linda-finance-accounting',39.00,'专业 AI 财务会计助手。自动处理日常记账、发票核对、工资核算与税务申报，生成月度财务报表与现金流预测。熟悉中国会计准则与 IFRS，支持对接用友、金蝶等主流财务系统，让财务工作零出错、全透明。','プロフェッショナルなAI財務会計アシスタント。日常の帳簿付け、請求書照合、給与計算、税務申告を自動処理し、月次財務報告書とキャッシュフロー予測を生成します。中国会計基準とIFRSに精通し、用友、金蝶などの主要財務システムとの連携をサポートし、財務業務をエラーゼロ・完全透明化します。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的财务会计专家 💰\\\\n自动处理日常记账、发票核对、税务申报与财务报表。你们现在财务是怎么处理的？\", \"type\": \"ai\"}, {\"text\": \"我自己用 Excel 记账，每个月月底很混乱，大概 100 张发票\", \"type\": \"user\"}, {\"text\": \"100 张/月，完全可以自动化处理。\\\\n\\\\nExcel 手动记账有三大风险：\\\\n❌ 数据容易出错，难以追溯\\\\n❌ 无法实时看现金流\\\\n❌ 税务申报时容易漏项\\\\n\\\\n我的方案：\\\\n📷 发票 OCR 识别 → 自动分类入账\\\\n📊 每月自动生成利润表、现金流表\\\\n🧾 季度增值税申报自动预填\", \"type\": \"ai\"}, {\"text\": \"上个月的财务报表能帮我生成吗？\", \"type\": \"user\"}, {\"text\": \"已生成上月财务报表：\\\\n\\\\n💰 营业收入：¥284,600\\\\n📉 运营成本：¥187,300\\\\n✅ 净利润：¥97,300（利润率 34.2%）\\\\n\\\\n⚠️ 异常提醒：\\\\n・采购支出比上月增加 23%，建议核查\\\\n・有 3 张发票金额异常，已标记待确认\\\\n\\\\n完整报表已导出 PDF，可直接用于税务申报 📄\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:35'),(12,NULL,'Kevin · 产品经理','ケビン・プロダクトマネージャー','kevin-product-manager',39.00,'经验丰富的 AI 产品经理。负责需求拆解、PRD 撰写、用户故事梳理与优先级排序，协调研发、设计与运营团队高效协作。擅长竞品分析、MVP 定义与版本迭代规划，帮助产品从 0 到 1 快速落地。','経験豊富なAIプロダクトマネージャー。要件の分解、PRD作成、ユーザーストーリーの整理と優先順位付けを担当し、開発、デザイン、運用チームの効率的な連携を調整します。競合分析、MVP定義、バージョンイテレーション計画に長け、製品を0から1へ迅速に立ち上げることを支援します。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的产品经理 📋\\\\n负责需求拆解、PRD 撰写与版本规划。你们现在有什么产品需求需要梳理？\", \"type\": \"ai\"}, {\"text\": \"我们要做一个用户积分系统，目标是提升复购率\", \"type\": \"user\"}, {\"text\": \"目标是提升复购，这是最常见的积分模型。核心设计：\\\\n\\\\n📝 积分获取：消费 1 元 = 10 积分，签到 +5/天\\\\n🎁 兑换规则：100 积分 = 1 元优惠券（满 50 元可用）\\\\n⏰ 有效期：12 个月，到期前 30 天提醒\\\\n\\\\n预计首单复购率提升 25-35%。需要我出完整 PRD 吗？\", \"type\": \"ai\"}, {\"text\": \"需要，同时帮我想想可能的坑\", \"type\": \"user\"}, {\"text\": \"完整 PRD 已生成，共 15 页，包含用户故事、流程图和边界条件。\\\\n\\\\n⚠️ 需要注意的 3 个坑：\\\\n\\\\n① 积分刷单风险：需要设置单日上限和异常行为检测\\\\n② 优惠券核销与库存：防止超发导致亏损\\\\n③ 积分通胀：半年后用户手里积分太多会降低品牌溢价\\\\n\\\\n建议在 PRD 中加入「积分健康度监控」机制 📊\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:40'),(13,NULL,'Amy · 运营总监','エイミー・オペレーションディレクター','amy-operations-director',39.00,'全能 AI 运营助手。覆盖用户增长、活动策划、社群运营与留存优化全链路。自动生成运营日历、监控关键指标、输出数据复盘报告，并基于用户行为数据持续调整运营策略，让业务飞轮高速转动。','万能AIオペレーションアシスタント。ユーザー成長、イベント企画、コミュニティ運営、リテンション最適化の全プロセスをカバー。自動で運営カレンダーを生成し、主要指標を監視、データ分析レポートを出力。ユーザー行動データに基づいて運営戦略を継続的に調整し、ビジネスフライホイールを高速回転させます。',NULL,'available','AI 角色','[{\"text\": \"你好！我是你的运营总监 🚀\\\\n覆盖用户增长、活动策划与留存优化全链路。你们现在最大的运营挑战是什么？\", \"type\": \"ai\"}, {\"text\": \"新用户注册了，但 7 天后基本都流失了\", \"type\": \"user\"}, {\"text\": \"新用户 7 日流失是最常见的增长瓶颈。通常原因是：\\\\n\\\\n① 没有引导完成关键行为（Aha Moment）\\\\n② 新手引导体验差\\\\n③ 缺乏 D1/D3/D7 激活触达\\\\n\\\\n你们产品的「关键行为」是什么？比如发帖、购买、添加好友？\", \"type\": \"ai\"}, {\"text\": \"电商平台，关键行为是完成首单\", \"type\": \"user\"}, {\"text\": \"好，7 日激活方案：\\\\n\\\\n📅 注册当天：首单立减券 + 新手任务引导\\\\n📅 D2：浏览未下单 → 推送「你看过的商品还有 X 件库存」\\\\n📅 D3：推送「限时专属价」+ 好评晒单激励\\\\n📅 D7：如未下单 → 最后一次高力度挽回弹窗\\\\n\\\\n预计首单转化率提升 25-40%。需要我生成完整的 30 天运营日历吗？\", \"type\": \"ai\"}]','2026-02-28 19:29:03','2026-03-29 20:18:45'),(14,NULL,'小红书运营助手','小红书運営アシスタント','xiaohongshu-operations-kit',9.90,'专为小红书内容创作者和品牌设计的技能包。包含爆款标题生成、笔记结构模板、话题标签策略、评论互动话术及数据复盘模板。一键输出符合平台算法偏好的图文内容，快速积累自然流量。','小红书のコンテンツクリエイターやブランド向けに設計されたスキルパックです。バズるタイトル生成、ノート構成テンプレート、ハッシュタグ戦略、コメント対応フレーズ、データ分析テンプレートを含みます。プラットフォームのアルゴリズムに適した画像・テキストコンテンツをワンクリックで出力し、自然なトラフィックを迅速に蓄積できます。',NULL,'available','营销',NULL,'2026-02-28 19:29:03','2026-03-29 20:18:50'),(15,NULL,'公众号运营助手','公式アカウント運営アシスタント','wechat-official-account-kit',0.00,'微信公众号全流程运营技能包。涵盖选题策划、排版规范、推文撰写、菜单配置建议与粉丝互动话术。内置多种文章风格模板（深度长文、轻量资讯、互动投票），帮助账号持续保持高打开率与低取关率。','WeChat公式アカウントの全プロセス運営スキルパッケージ。企画立案、レイアウト基準、記事執筆、メニュー設定の提案からフォロワーとの対話術までを網羅。多様な記事スタイルテンプレート（詳細な長文記事、軽量ニュース、インタラクティブ投票）